/**
 * Assert that a HookResult does not carry a wrong-event hookEventName.
 * Allowed: undefined, or exactly `expectedEvent`.
 * Forbidden: any other string (especially 'UserPromptSubmit' on lifecycle events).
 */
function assertNoWrongHookEventName(result: HookResult, firingEvent: string): void {
  const hso = result.hookSpecificOutput as Record<string, unknown> | undefined;
  if (!hso) return;
  const hen = hso.hookEventName;
  if (hen === undefined) return;
  expect(hen, `hookEventName must match firing event '${firingEvent}' or be absent`).toBe(firingEvent);
}

/**
 * Assert that a HookResult does not carry additionalContext for events where
 * CC does not read it.
 */
function assertNoAdditionalContext(result: HookResult, firingEvent: string): void {
  const hso = result.hookSpecificOutput as Record<string, unknown> | undefined;
  if (!hso) return;
  expect(
    hso.additionalContext,
    `additionalContext must be absent for ${firingEvent} — CC does not read it for this event`
  ).toBeUndefined();
}

